python3 -c "
import openpyxl
wb = openpyxl.load_workbook('input.xlsx')
for sn in wb.sheetnames:
    ws = wb[sn]
    print(f'=== {sn} === (rows={ws.max_row}, cols={ws.max_column})')
    for row in ws.iter_rows(min_row=1, max_row=min(ws.max_row, 30), max_col=min(ws.max_column, 6), values_only=False):
        for cell in row:
            if cell.value is not None:
                fill_rgb = None
                if cell.fill and cell.fill.fgColor and cell.fill.fgColor.rgb:
                    fill_rgb = cell.fill.fgColor.rgb
                print(f'  {cell.coordinate}: {cell.value!r}  fill={fill_rgb}')
"
